package com.up.projectmanager.data

import com.up.projectmanager.model.Difficulty
import com.up.projectmanager.model.Subject

object QuizRepository {

    fun getQuestions(subject: Subject, difficulty: Difficulty): List<Question> {
        val allQuestions = when (subject) {
            Subject.ANCIENT -> ancientQuestions
            Subject.MEDIEVAL -> medievalQuestions
            Subject.MODERN -> modernQuestions
        }
        val filtered = allQuestions.filter { it.first == difficulty }
        return filtered.shuffled().take(5).map { it.second }
    }

